// components/fields/Object.tsx

import React, {useMemo} from 'react';
import {type FieldValues} from 'react-hook-form';
import type {IObjectGroup, UseFieldLogicElementProps} from "@lmb-it/kitsconcerto-types";
import {Flex, Text} from "../../../../_compat";
import {Label} from "../../../../_compat";
import {FormRenderer} from "../../FormRenderer";

/**
 * Renders a static, non-repeatable group of fields (a nested object).
 * It provides a layout wrapper and recursively renders its children with the correct nested path.
 */
export const ObjectElement = <T extends FieldValues>({
                                                  element,
                                                  control,
                                                  getValues,
                                                  groupField,
                                                  focusedField,
                                                  setFocusedField,
                                                  fieldLogic,
                                              }: UseFieldLogicElementProps<T>) => {

    // 1. Get the object's own dynamic state (visibility, layout, label) from the logic hook.
    const {isShown, label, elements, helperText, style: elementStyle} = fieldLogic;

    const objectElement = element as IObjectGroup<T>;
    const {grid} = objectElement;

    const renderer = useMemo(() => {
        if (!elements) {
            return null;
        }
        return <FormRenderer
            elements={elements}
            control={control}
            getValues={getValues}
            groupField={groupField}
            parentPath={`${element.id.toString()}.`}
            focusedField={focusedField}
            setFocusedField={setFocusedField!}
            grid={grid}
        />
    }, [elements, focusedField, groupField, grid])

    if (!isShown) {
        return null;
    }

    return (
        <Flex id={element.id.toString()} w="full" flexDirection="column" gap={10} {...(elementStyle?.container || {})}>
            {label && (
                <Label as="h2" label={label} elementId={element.id as string}/>
            )}

            {helperText && typeof helperText != "function" && (
                <Text fontSize={10} as={"small"}>
                    {helperText}
                </Text>
            )}
            {/*
                  Unlike Group, we don't map over `fields`. We render the FormRenderer once,
                  passing it the child elements and the new parent path.
                  This ensures fields are registered correctly (e.g., 'address.street').
                */}

            {renderer}
        </Flex>
    );
};

export default ObjectElement
